using NP std;
NP phigrOS
{
    il ll read()
    {
        ll x=0,f=1;char ch=gc();
        wh(ch<'0'||ch>'9'){if(ch=='-')f=-1;ch=getchar();}
        wh(ch>='0'&&ch<='9'){x=x*10+ch-'0';ch=gc();}
        return x*f;
    }
    void write(ll x)
    {
        if(x<0)pc('-'),x=-x;
        if(x>9)write(x/10);
        pc(x%10+'0');
    }
    void writeln(ll x)
    {
        write(x);
        puts("");
        return;
    }
}
using NP phigrOS;
CI MAXN=1e5+5;
int match[MAXN],n,m,ans,st[MAXN];
vector<int> g[MAXN];
vector<PII> v; 
bool find(int x)
{
	FOI(s,g[x])
	{
		if(st[s])continue;
		st[s]=true;
		if(match[s]==0||find(match[s]))
		{
			match[s]=x;
			return true;
		}
	} 
	return false;
}
signed main(void)
{

    //freopen(".in","r",stdin);
    //freopen(".out","w",stdout);
	ios::sync_with_stdio(0);
	cin.tie(0);
	cin>>n>>m;
	wh(1)
	{
		int u,v;
		cin>>u>>v;
		if(u==-1&&v==-1)break;
		g[u].pb(v); 
	} 
	FOR(i,1,n)
	{
		cl(st);
		if(find(i))
		{
			++ans;
		}
	}
	cout<<ans<<'\n';
	FOR(i,n+1,m)
	{
		if(match[i])
		{
			cout<<match[i]<<' '<<i<<'\n';
		}
	}
    return false;
}
